previewCss:
.darma-loader-darma-custom-336 {color: var(--loader-color, #f97316);
  --loader-secondary-color: #facc15;
  --loader-bg: #ffffff;
  --b: 25%;
  height: 70px;
  aspect-ratio: 1/cos(30deg);
  position: relative;
  clip-path: polygon(50% 0,100% 100%,0 100%,50% 0,50% var(--b),calc(var(--b)*cos(30deg)) calc(100% - var(--b)/2),calc(100% - var(--b)*cos(30deg)) calc(100% - var(--b)/2),50% var(--b));
  filter: blur(12px);
}.darma-loader-darma-custom-336:before {content: "";
  position: absolute;
  inset: -8% 0;
  background: conic-gradient(#0000 35%,var(--loader-secondary-color, #facc15),#0000 65%);
  animation: darma-loader-darma-custom-336-l5 2s linear infinite;
}@keyframes darma-loader-darma-custom-336-l5 {to {rotate: 1turn}}

